import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"不朽","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/不朽.md","filePath":"4.资源分区/6.技艺及称号/杂项/不朽.md"}'),o={name:"4.资源分区/6.技艺及称号/杂项/不朽.md"};function d(b,e,l,i,_,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"不朽",tabindex:"-1"},[n("不朽 "),r("a",{class:"header-anchor",href:"#不朽","aria-label":'Permalink to "不朽"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),s('<h1 id="不朽-1" tabindex="-1">不朽 <a class="header-anchor" href="#不朽-1" aria-label="Permalink to &quot;不朽&quot;">​</a></h1><p>不朽</p><p>“我们曾认为他们永恒不朽……直到他们血染大地”<br> ——被遗失的文档<br> 在某个世界，巨人并非是传说中的生物<br> 他们一度成为了整个世界的主宰，从未有人见过巨人死去<br> 直到第一个人发现了巨人永生之密，那人与他知晓的秘密一同消失<br> 但是他也带走了所有的永生，自那以后，再也没有真正的不朽<br> 巨人们死去了，但是他们的血肉与躯壳，以腐烂又永恒生长共存的扭曲姿态，仍在行走<br> 人们从死去巨人的身上继承了整个世界，直至终结</p><p>不灭之握 C+1000</p><p>“他们的杯中曾经满溢生命之水，他们的腕力曾将整个世界握于手中，但现在只剩下了烂泥中的骸骨”</p><p>你饮下了不朽者守护的生命之泉，因此，你获得了永恒成长的能力，但是不朽已经不在，你的成长只能从其他生物身上汲取<br> 现在，当你在战斗中经过三轮时，你的身体已经在战斗中做好了吸取敌方生物的准备，此时你的小臂以下会呈现病态的惨绿，如果有武器，武器也会有这个效果<br> 这会使你的下次攻击会获得耐力传奇属性*2点DP，并且为你提供2点临时生命。<br> 攻击后这会永久为你提供1点生命上限，这个效果一个影片只能触发一次。</p><p>过度生长 D+500</p><p>“他们那大脑已死的躯壳仍在不断生长……即使已经扭曲变形……即使已经腐臭不堪……”</p><p>现在，你的身体将在死去前永恒的增长，即使那是病态且了无生趣的，<br> 在经过一场同级的战斗并且至少死亡一个敌人之后，你永久获得1点生命上限，这个效果一个影片最多触发一次，至多5次。<br> 此外，在上述效果生效三次之后，你的身体将更加深陷这腐臭的永生泥潭，因此不在因为伤势而昏迷。</p><p>骸骨镀层 D+500</p><p>“他们的骨骼不似骨骼，更像金属，那些腐烂的躯壳，他们仍然行走在大地上，骨骼包裹着内脏，活像行走的骷髅”</p><p>你披上了甲胄——由你自己的骨骼制成的甲胄，他们从你的体内破体而出，疼痛只是附赠品<br> 无论如何，坚硬的骨骼切实的保护了你的身躯，幸亏你的肉体还没有腐烂，否则伤口将永恒存在</p><p>现在，当你在场景内第一次受到攻击时，你的骨骼会突兀的生长并且刺穿皮肤，为你挡下这次攻击<br> 这视作你在本场景获得基于天生防御的【全伤害吸收1】和3点天生防御。<br> 这之后，多余的部分会脱落，其余部分会收回你的体内，等待下次生效<br> 每次使用这一效果会使你不可避免的受到一点严重伤害和一点不可豁免的剧痛点数。</p><p>坚定 D+500</p><p>“尽管无法证明他们还保留着思维能力，但是他们仍在行动，他们求生的意志已经让他们变成了生命的奴隶”</p><p>你的身体现在本能的寻求着生存，这已经无关你的意志了，但是这依旧保护了你的精神和肉体<br> 而当你真正遇上危机时，你的身体会持续的避开一切危险直到恢复健康，这甚至不需要经过你的同意<br> 在你的完好生命值不足一半时，你获得1点【异常点治疗】（24治疗点）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
